if (input.trigger === "idle" && deps.noteIsEmpty(input.note)) {
      const now = deps.clockNow();
      const event: EmptyNoteDiscarded = {
        kind: "empty-note-discarded",
        noteId: input.noteId,
        occurredOn: now,
      };
      deps.publish(event);
      return { ok: true, value: { kind: "empty-discarded", event } };
    }
